item.command:
/bin/zsh -lc 'for f in crates/*/Cargo.toml; do awk -v file="$f" '"'
  /"'^'"\\[["'^]]+'"\\]/ { section="'$0 }
  section ~ /''^'"\\[(dependencies|dev-dependencies|build-dependencies)\\]"'$/ && /''^[[:space:]]*orbit-knowledge[[:space:]]*=/ {
    printf "%s:%d:%s'"\\n\", file, NR, section
  }
' \""'$f"; done'

