/bin/zsh -lc "for f in crates/orbit-cli/Cargo.toml crates/orbit-tools/Cargo.toml; do awk '
  /"'^name[[:space:]]*=/ && !name { gsub(/"/,"",$3); name=$3 }
  END { printf "%s -> %s'"\\n\", name, FILENAME }
' \""'$f"; done'

